     1вЖТexport const checkInternalAccess = (host: string | undefined): boolean => {
     2вЖТ	if (!host) return false;
     3вЖТ
     4вЖТ	const hostname = host.split(':')[0]?.toLowerCase();
     5вЖТ	if (!hostname) return false;
     6вЖТ
     7вЖТ	const allowedDomains = [
     8вЖТ		'.in.customink.com',
     9вЖТ		'.in.staging.customink.com',
    10вЖТ		'.k8s-dev.customink.com',
    11вЖТ		'localhost',
    12вЖТ	];
    13вЖТ
    14вЖТ	return allowedDomains.some(
    15вЖТ		(domain) => hostname === domain.substring(1) || hostname.endsWith(domain),
    16вЖТ	);
    17вЖТ};
