     1вЖТimport { createHash } from 'crypto';
     2вЖТ
     3вЖТimport { STYLES_HASHING_ALGORITHM } from '@constants/common.constant';
     4вЖТ
     5вЖТconst sortKeys = (obj: unknown): unknown => {
     6вЖТ	if (obj === null) {
     7вЖТ		return obj;
     8вЖТ	}
     9вЖТ
    10вЖТ	if (typeof obj === 'function') {
    11вЖТ		return obj.toString();
    12вЖТ	}
    13вЖТ
    14вЖТ	if (typeof obj !== 'object') {
    15вЖТ		return obj;
    16вЖТ	}
    17вЖТ
    18вЖТ	if (Array.isArray(obj)) {
    19вЖТ		return obj.map(sortKeys);
    20вЖТ	}
    21вЖТ
    22вЖТ	const sorted: Record<string, unknown> = {};
    23вЖТ	Object.keys(obj as Record<string, unknown>)
    24вЖТ		.sort()
    25вЖТ		.forEach((key) => {
    26вЖТ			sorted[key] = sortKeys((obj as Record<string, unknown>)[key]);
    27вЖТ		});
    28вЖТ
    29вЖТ	return sorted;
    30вЖТ};
    31вЖТ
    32вЖТexport const hashFromObject = ({ obj }: { obj: Record<string, unknown> }): string => {
    33вЖТ	const sortedObj = sortKeys(obj);
    34вЖТ	const jsonString = JSON.stringify(sortedObj);
    35вЖТ	return createHash(STYLES_HASHING_ALGORITHM).update(jsonString).digest('hex');
    36вЖТ};
