     9вЖТexport const setupSwagger = (
    10вЖТ	app: INestApplication,
    11вЖТ	fastifyAdapter: FastifyAdapter,
    12вЖТ	globalPrefix: string,
    13вЖТ): void => {
    14вЖТ	const fastifyInstance = fastifyAdapter.getInstance();
    15вЖТ
    16вЖТ	fastifyInstance.addHook('preHandler', (request, reply, done): void => {
    17вЖТ		if (request.url.startsWith('/swagger')) {
    18вЖТ			if (!checkInternalAccess(request.headers.host)) {
    19вЖТ				void reply.code(403).send(INTERNAL_VPN_ACCESS_ERROR);
    20вЖТ				return;
    21вЖТ			}
    22вЖТ		}
    23вЖТ		done();
    24вЖТ	});
    25вЖТ
    26вЖТ	const openApiConfig = new DocumentBuilder()
    27вЖТ		.addServer(globalPrefix)
    28вЖТ		.setTitle('Recommendations service')
    29вЖТ		.setDescription('Recommendations service API.')
    30вЖТ		.setVersion('1.0.0')
    31вЖТ		.build();
    32вЖТ	const document = SwaggerModule.createDocument(app, openApiConfig);
    33вЖТ
    34вЖТ	SwaggerModule.setup('swagger', app, document);
    35вЖТ};
