     1вЖТexport function shuffleArray<T>({ array }: { array: T[] }): T[] {
     2вЖТ	const shuffled = [...array];
     3вЖТ	for (let i = shuffled.length - 1; i > 0; i--) {
     4вЖТ		const j = Math.floor(Math.random() * (i + 1));
     5вЖТ		[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]] as [T, T];
     6вЖТ	}
     7вЖТ	return shuffled;
     8вЖТ}
     9вЖТ
    10вЖТexport function injectItemsRandomlyInFirstN<T>({
    11вЖТ	items,
    12вЖТ	targetArray,
    13вЖТ	firstN,
    14вЖТ}: {
    15вЖТ	items: T[];
    16вЖТ	targetArray: T[];
    17вЖТ	firstN: number;
    18вЖТ}): T[] {
    19вЖТ	if (items.length === 0) {
    20вЖТ		return [...targetArray];
    21вЖТ	}
    22вЖТ
    23вЖТ	const result = [...targetArray];
    24вЖТ	const numberOfItemsToInject = items.length;
    25вЖТ	const maxPosition = Math.max(firstN, numberOfItemsToInject);
    26вЖТ	const availablePositions = Array.from({ length: maxPosition }, (_, i) => i);
    27вЖТ	const shuffledPositions = shuffleArray(availablePositions);
    28вЖТ	const selectedPositions = shuffledPositions
    29вЖТ		.slice(0, numberOfItemsToInject)
    30вЖТ		.sort((a, b) => a - b);
    31вЖТ
    32вЖТ	for (let i = 0; i < numberOfItemsToInject; i++) {
    33вЖТ		const position = selectedPositions[i];
    34вЖТ		const item = items[i];
    35вЖТ		if (position !== undefined && item !== undefined) {
    36вЖТ			result.splice(position, 0, item);
    37вЖТ		}
    38вЖТ	}
    39вЖТ
    40вЖТ	return result;
    41вЖТ}
